const xml = $input.first().json.data || '';
const config = $('Set YouTube research topic').first().json;
const text = (str = '') => str.replace(/<[^>]*>/g, '').trim();
const matches = [...xml.matchAll(/<entry>([\s\S]*?)<\/entry>/gi)].slice(0, 8);
return matches.map((match) => {
  const entry = match[1];
  const title = text((entry.match(/<title[^>]*>([\s\S]*?)<\/title>/i) || [])[1] || '');
  const videoId = (entry.match(/<yt:videoId>([\s\S]*?)<\/yt:videoId>/i) || [])[1] || '';
  const channel = text((entry.match(/<author>[\s\S]*?<name>([\s\S]*?)<\/name>[\s\S]*?<\/author>/i) || [])[1] || 'YouTube Channel');
  const published = (entry.match(/<published>([\s\S]*?)<\/published>/i) || [])[1] || new Date().toISOString();
  const sourceUrl = videoId ? `https://www.youtube.com/watch?v=${videoId}` : `https://www.youtube.com/results?search_query=${encodeURIComponent(config.searchQuery)}`;
  return {
    json: {
      workspaceId: config.workspaceId,
      title: `YouTube Video: ${title}`,
      sourceUrl,
      publishedAt: published,
      sourceName: 'YouTube RSS Collector',
      sourceType: 'media',
      content: `Trending YouTube content related to query '${config.searchQuery}'. Video title: ${title}. Channel: ${channel}. Public video link: ${sourceUrl}.` 
    }
  };
});
